"use client"

import * as React from "react"

import {
  Example,
  ExampleWrapper,
} from "@/registry/bases/base/components/example"
import { Button } from "@/registry/bases/base/ui/button"
import {
  Stepper,
  StepperDescription,
  StepperItem,
  StepperList,
  StepperPanel,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/bases/base/ui/stepper"

export default function StepperExample() {
  return (
    <ExampleWrapper className="lg:grid-cols-1">
      <StepperHorizontal />
      <StepperVertical />
    </ExampleWrapper>
  )
}

const steps = [
  {
    title: "Account",
    description: "Create your account",
    content: "Enter your email address and choose a secure password to get started.",
  },
  {
    title: "Profile",
    description: "Set up your profile",
    content: "Add your name, avatar, and other details to personalise your experience.",
  },
  {
    title: "Review",
    description: "Review and submit",
    content: "Check your details and confirm everything looks correct before submitting.",
  },
]

function StepperHorizontal() {
  const [activeStep, setActiveStep] = React.useState(0)

  const isFirstStep = activeStep === 0
  const isLastStep = activeStep === steps.length - 1

  return (
    <Example title="Horizontal">
      <div className="w-full space-y-6">
        <Stepper
          activeStep={activeStep}
          onActiveStepChange={setActiveStep}
          orientation="horizontal"
        >
          <StepperList>
            {steps.map((step, index) => (
              <React.Fragment key={step.title}>
                {index > 0 && <StepperSeparator />}
                <StepperItem step={index}>
                  <StepperTrigger>
                    <span className="flex size-8 shrink-0 items-center justify-center rounded-full border text-sm font-medium data-[state=active]:border-foreground data-[state=active]:bg-foreground data-[state=active]:text-background data-[state=completed]:border-foreground data-[state=completed]:bg-foreground data-[state=completed]:text-background">
                      {index < activeStep ? "âś“" : index + 1}
                    </span>
                    <div className="hidden sm:flex sm:flex-col sm:gap-0.5">
                      <StepperTitle>{step.title}</StepperTitle>
                      <StepperDescription>{step.description}</StepperDescription>
                    </div>
                  </StepperTrigger>
                </StepperItem>
              </React.Fragment>
            ))}
          </StepperList>

          {steps.map((step, index) => (
            <StepperPanel key={step.title} step={index} className="rounded-lg border p-6">
              <h3 className="text-sm font-semibold">{step.title}</h3>
              <p className="mt-1 text-sm text-muted-foreground">{step.content}</p>
            </StepperPanel>
          ))}
        </Stepper>

        <div className="flex justify-between">
          <Button
            variant="outline"
            onClick={() => setActiveStep((s) => s - 1)}
            disabled={isFirstStep}
          >
            Previous
          </Button>
          <Button
            onClick={() => setActiveStep((s) => s + 1)}
            disabled={isLastStep}
          >
            {isLastStep ? "Finish" : "Next"}
          </Button>
        </div>
      </div>
    </Example>
  )
}

function StepperVertical() {
  const [activeStep, setActiveStep] = React.useState(0)

  const isFirstStep = activeStep === 0
  const isLastStep = activeStep === steps.length - 1

  return (
    <Example title="Vertical">
      <div className="w-full space-y-6">
        <Stepper
          activeStep={activeStep}
          onActiveStepChange={setActiveStep}
          orientation="vertical"
        >
          <StepperList>
            {steps.map((step, index) => (
              <React.Fragment key={step.title}>
                {index > 0 && <StepperSeparator />}
                <StepperItem step={index}>
                  <StepperTrigger>
                    <span className="flex size-8 shrink-0 items-center justify-center rounded-full border text-sm font-medium data-[state=active]:border-foreground data-[state=active]:bg-foreground data-[state=active]:text-background data-[state=completed]:border-foreground data-[state=completed]:bg-foreground data-[state=completed]:text-background">
                      {index < activeStep ? "âś“" : index + 1}
                    </span>
                    <div className="flex flex-col gap-0.5">
                      <StepperTitle>{step.title}</StepperTitle>
                      <StepperDescription>{step.description}</StepperDescription>
                    </div>
                  </StepperTrigger>
                </StepperItem>
              </React.Fragment>
            ))}
          </StepperList>

          <div className="flex-1">
            {steps.map((step, index) => (
              <StepperPanel
                key={step.title}
                step={index}
                className="rounded-lg border p-6"
              >
                <h3 className="text-sm font-semibold">{step.title}</h3>
                <p className="mt-1 text-sm text-muted-foreground">
                  {step.content}
                </p>
              </StepperPanel>
            ))}
          </div>
        </Stepper>

        <div className="flex justify-between">
          <Button
            variant="outline"
            onClick={() => setActiveStep((s) => s - 1)}
            disabled={isFirstStep}
          >
            Previous
          </Button>
          <Button
            onClick={() => setActiveStep((s) => s + 1)}
            disabled={isLastStep}
          >
            {isLastStep ? "Finish" : "Next"}
          </Button>
        </div>
      </div>
    </Example>
  )
}

