"use client"

import * as React from "react"

import { cn } from "@/registry/bases/base/lib/utils"

// â”€â”€â”€ Types â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

type StepperOrientation = "horizontal" | "vertical"
type StepperState = "active" | "completed" | "inactive"

// â”€â”€â”€ Root context â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

type StepperContextValue = {
  activeStep: number
  setActiveStep: (step: number) => void
  orientation: StepperOrientation
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

// â”€â”€â”€ Per-item context â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

type StepperItemContextValue = {
  step: number
  state: StepperState
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// â”€â”€â”€ Stepper (root) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

type StepperProps = React.ComponentProps<"div"> & {
  activeStep?: number
  defaultActiveStep?: number
  onActiveStepChange?: (step: number) => void
  orientation?: StepperOrientation
}

function Stepper({
  activeStep: activeStepProp,
  defaultActiveStep = 0,
  onActiveStepChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: StepperProps) {
  const [internalActiveStep, setInternalActiveStep] =
    React.useState(defaultActiveStep)

  const activeStep =
    activeStepProp !== undefined ? activeStepProp : internalActiveStep

  const setActiveStep = React.useCallback(
    (step: number) => {
      if (activeStepProp === undefined) {
        setInternalActiveStep(step)
      }
      onActiveStepChange?.(step)
    },
    [activeStepProp, onActiveStepChange]
  )

  return (
    <StepperContext.Provider value={{ activeStep, setActiveStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "cn-stepper flex gap-6",
          orientation === "horizontal" ? "flex-col" : "flex-row",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// â”€â”€â”€ StepperList â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

function StepperList({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-list"
      className={cn(
        "cn-stepper-list flex",
        orientation === "horizontal" ? "flex-row items-center" : "flex-col",
        className
      )}
      {...props}
    />
  )
}

// â”€â”€â”€ StepperItem â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

type StepperItemProps = React.ComponentProps<"div"> & {
  step: number
}

function StepperItem({ step, className, children, ...props }: StepperItemProps) {
  const { activeStep } = useStepper()

  const state: StepperState =
    step < activeStep
      ? "completed"
      : step === activeStep
        ? "active"
        : "inactive"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        className={cn("cn-stepper-item flex items-center", className)}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// â”€â”€â”€ StepperTrigger â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { setActiveStep } = useStepper()
  const { step, state } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={state}
      className={cn(
        "cn-stepper-trigger inline-flex items-center gap-2 rounded-md text-left transition-colors outline-none",
        "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      onClick={() => setActiveStep(step)}
      {...props}
    >
      {children}
    </button>
  )
}

// â”€â”€â”€ StepperTitle â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  const { state } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "cn-stepper-title text-sm font-medium leading-none",
        state === "inactive" ? "text-muted-foreground" : "text-foreground",
        className
      )}
      {...props}
    />
  )
}

// â”€â”€â”€ StepperDescription â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn(
        "cn-stepper-description text-sm text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// â”€â”€â”€ StepperSeparator â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      className={cn(
        "cn-stepper-separator shrink-0 bg-border",
        orientation === "horizontal"
          ? "h-px flex-1"
          : "mx-3 w-px self-stretch min-h-4",
        className
      )}
      {...props}
    />
  )
}

// â”€â”€â”€ StepperPanel â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

type StepperPanelProps = React.ComponentProps<"div"> & {
  step: number
}

function StepperPanel({ step, className, ...props }: StepperPanelProps) {
  const { activeStep } = useStepper()
  const isActive = step === activeStep

  return (
    <div
      data-slot="stepper-panel"
      data-state={isActive ? "active" : "inactive"}
      hidden={!isActive}
      className={cn("cn-stepper-panel", className)}
      {...props}
    />
  )
}

// â”€â”€â”€ Exports â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

export {
  Stepper,
  StepperList,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
  useStepper,
  useStepperItem,
}

